const d1  = $('Buscar Hoje').first().json;
const d7  = $('Buscar Semana').first().json;
const d30 = $('Buscar 30 dias').first().json;
const d90 = $input.first().json;

function fmt(s) {
  const [y, m, d] = s.split('-');
  return d + '/' + m + '/' + y;
}
function fmtShort(s) {
  const [y, m, d] = s.split('-');
  return d + '/' + m;
}
function brl(v) {
  const num = parseFloat(v) || 0;
  const parts = Math.abs(num).toFixed(2).split('.');
  parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return 'R$ ' + parts[0] + ',' + parts[1];
}
function brl8(v) {
  const num = parseFloat(v) || 0;
  return 'R$ ' + Math.abs(num).toFixed(8).replace('.', ',');
}
function pct(a, b) {
  if (!b) return '0,00';
  return (parseFloat(a) / parseFloat(b) * 100).toFixed(2).replace('.', ',');
}
function deltaLabel(v) {
  const n = parseFloat(v);
  if (n > 0) return 'positivo';
  if (n < 0) return 'negativo';
  return 'neutro';
}

const meses = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
function fmtMes(s) {
  const [y, m] = s.split('-');
  return meses[parseInt(m, 10) - 1] + '/' + y;
}

// ── Usuários ──────────────────────────────────────────────────────────────────
const u1 = d1.usuarios;
const f1 = d1.financeiro;
const taxaConversao = (u1.investindo / u1.total * 100).toFixed(2).replace('.', ',');

const blocoUsuarios = [
  '👥 Usuários',
  '',
  'Usuários criados: ' + u1.total,
  'Usuários investindo: ' + u1.investindo,
  'Taxa de Conversão: ' + taxaConversao + '%',
  'Total investido: ' + brl(f1.volume_investido),
  'Ticket Médio: ' + (u1.investindo > 0 ? brl(f1.volume_investido / u1.investindo) : 'R$ 0,00'),
].join('\n');

// ── Lulu ──────────────────────────────────────────────────────────────────────
const luluTaxas        = f1.lulu_taxas_deposito_total    || 0;
const luluDeduzido     = f1.lulu_valor_deduzido_total    || 0;
const luluTaxasTotal   = f1.lulu_taxas_deposito_total    || 0;
const luluDeduzidoTotal = f1.lulu_valor_deduzido_total   || 0;
const luluPct = luluTaxasTotal > 0
  ? (luluDeduzidoTotal / luluTaxasTotal * 100).toFixed(2).replace('.', ',')
  : '0,00';

const luluRestante = luluTaxas - luluDeduzido;

const blocoLulu = [
  '💳 Lulu (taxas)',
  '',
  'Taxas Efí Bank (Total): ' + brl(luluTaxas),
  'Recuperado: ' + brl8(luluDeduzido),
  'Recuperado (%): ' + luluPct + '%',
  'Taxas Efí Bank (Restante): ' + brl(luluRestante),
].join('\n');

// ── Hoje ──────────────────────────────────────────────────────────────────────
const usuariosHojeTexto = u1.novos > 0
  ? 'Houveram ' + u1.novos + ' novos cadastros hoje.'
  : 'Não houveram novos cadastros hoje.';

const blocoHoje = [
  '📅 Hoje',
  '',
  usuariosHojeTexto,
  '',
  'Depósitos: ' + brl(f1.depositos),
  'Saques: ' + brl(f1.saques),
  'Delta: ' + brl(f1.delta) + ' (' + deltaLabel(f1.delta) + ')',
].join('\n');

// ── Projeção ──────────────────────────────────────────────────────────────────
const projecao = (d1.projecao_6_meses || []).map(function(p) {
  return '  ' + fmtMes(p.mes) + ': ' + brl(p.total_previsto);
}).join('\n');

const blocoProjecao = [
  '📈 Projeção das Metas (6 meses)',
  '',
  projecao || 'Nenhuma meta ativa.',
].join('\n');

// ── Histórico (7, 30, 90 dias) ────────────────────────────────────────────────
function blocoHistorico(d, label) {
  const u = d.usuarios;
  const f = d.financeiro;
  const base = u.total - u.novos;
  return [
    '📅 ' + label + ' (' + fmtShort(d.data_inicio) + ' a ' + fmtShort(d.data_referencia) + ')',
    '',
    'Tivemos o cadastro de ' + u.novos + ' novos usuários (+' + pct(u.novos, base) + '%) do total de ' + u.total + ' usuários no período.',
    '',
    'Depósitos: ' + brl(f.depositos),
    'Saques: ' + brl(f.saques),
    'Delta: ' + brl(f.delta) + ' (' + deltaLabel(f.delta) + ')',
  ].join('\n');
}

const historico = [
  blocoHistorico(d7,  'Últimos 7 dias'),
  '',
  '',
  blocoHistorico(d30, 'Últimos 30 dias'),
  '',
  '',
  blocoHistorico(d90, 'Últimos 90 dias'),
].join('\n');

// ── Estrutura principal ───────────────────────────────────────────────────────
const estrutura = [
  '📋 Resumo Operacional - ' + fmt(d1.data_referencia),
  '',
  blocoUsuarios,
  '',
  blocoLulu,
  '',
  blocoHoje,
  '',
  blocoProjecao,
].join('\n');

// ── Prompt para o AI ──────────────────────────────────────────────────────────
const chatInput = [
  'Voce e um assistente executivo da Purg.',
  'Com base nos dados abaixo, escreva EXATAMENTE 2 paragrafos curtos e suscintos de analise comparativa.',
  'Cada paragrafo deve ter no maximo 2 frases. Cubra angulos diferentes: um sobre usuarios, outro sobre financeiro.',
  'Regras: texto simples, sem asteriscos, sem markdown, sem introducao, sem assinatura.',
  '',
  estrutura,
].join('\n');

return [{ json: { estrutura, chatInput, historico } }];

